namespace sv_aea6abbb8423404ca5a9219d439b3479.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@* Vertical navigation tabs for settings sections *@

<nav class="settings-sidebar" aria-label="Settings navigation">
    <ul class="nav flex-column">
        @foreach (var section in _sections)
        {
            <li class="nav-item">
                <button class="nav-link w-100 text-start @(ActiveSection == section.Key ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section.Key)"
                        aria-current="@(ActiveSection == section.Key ? "page" : null)">
                    <span class="bi @section.Icon me-2" aria-hidden="true"></span>
                    @section.Label
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    [Parameter, EditorRequired]
    public string ActiveSection { get; set; } = "";

    [Parameter, EditorRequired]
    public EventCallback<string> OnSectionChanged { get; set; }

    private readonly record struct SectionInfo(string Key, string Label, string Icon);

    private static readonly SectionInfo[] _sections =
    [
        new("profile", "Profile", "bi-person-fill"),
        new("notifications", "Notifications", "bi-bell-fill"),
        new("security", "Security", "bi-shield-lock-fill"),
        new("appearance", "Appearance", "bi-palette-fill"),
    ];
}

@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Profile Settings</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_profile is not null)
    {
        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label for="displayName" class="form-label">Display Name</label>
                    <input id="displayName" type="text" class="form-control"
                           @bind="_displayName" @bind:event="oninput" />
                </div>

                <div class="mb-3">
                    <label for="email" class="form-label">Email</label>
                    <input id="email" type="email" class="form-control"
                           @bind="_email" @bind:event="oninput" />
                </div>

                <div class="mb-3">
                    <label for="bio" class="form-label">Bio</label>
                    <textarea id="bio" class="form-control" rows="4"
                              @bind="_bio" @bind:event="oninput"></textarea>
                </div>
            </div>

            <div class="col-md-4">
                <div class="text-center">
                    <label class="form-label d-block">Avatar Preview</label>
                    <div class="avatar-preview mb-2">
                        @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                        {
                            <img src="@_avatarUrl" alt="Avatar" class="rounded-circle img-fluid"
                                 style="width: 120px; height: 120px; object-fit: cover;" />
                        }
                        else
                        {
                            <div class="rounded-circle bg-secondary d-flex align-items-center justify-content-center"
                                 style="width: 120px; height: 120px; margin: 0 auto;">
                                <span class="bi bi-person-fill text-white" style="font-size: 3rem;"></span>
                            </div>
                        }
                    </div>
                    <div class="mb-3">
                        <label for="avatarUrl" class="form-label">Avatar URL</label>
                        <input id="avatarUrl" type="url" class="form-control form-control-sm"
                               @bind="_avatarUrl" @bind:event="oninput" />
                    </div>
                </div>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
                }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@_saving">
                Discard Changes
            </button>
        </div>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success alert-dismissible mt-3" role="alert">
                @_successMessage
                <button type="button" class="btn-close" @onclick="() => _successMessage = null"
                        aria-label="Close"></button>
            </div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger alert-dismissible mt-3" role="alert">
                @_errorMessage
                <button type="button" class="btn-close" @onclick="() => _errorMessage = null"
                        aria-label="Close"></button>
            </div>
        }
    }
</div>

@code {
    private UserProfile? _profile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadProfileAsync();
    }

    private async Task LoadProfileAsync()
    {
        _loading = true;
        _profile = await SettingsService.GetProfileAsync();
        PopulateFields(_profile);
        _loading = false;
    }

    private void PopulateFields(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _profile = updated;
            _successMessage = "Profile saved successfully!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save profile: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_profile is not null)
        {
            PopulateFields(_profile);
        }
        _successMessage = null;
        _errorMessage = null;
    }
}

@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Notification Preferences</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_prefs is not null)
    {
        <div class="mb-4">
            <h5>General</h5>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            @if (_channels.Count == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                <div class="list-group">
                    @foreach (var channel in _channels)
                    {
                        <label class="list-group-item d-flex align-items-center gap-2">
                            <input class="form-check-input mt-0" type="checkbox"
                                   checked="@channel.Muted"
                                   @onchange="e => ToggleChannel(channel.Name, (bool)(e.Value ?? false))" />
                            <span>@channel.Name</span>
                            @if (channel.Muted)
                            {
                                <span class="badge bg-secondary ms-auto">Muted</span>
                            }
                        </label>
                    }
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @if (_saving)
            {
                <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
            }
            Save Preferences
        </button>

        @if (_successMessage is not null)
        {
            <div class="alert alert-success alert-dismissible mt-3" role="alert">
                @_successMessage
                <button type="button" class="btn-close" @onclick="() => _successMessage = null"
                        aria-label="Close"></button>
            </div>
        }

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger alert-dismissible mt-3" role="alert">
                @_errorMessage
                <button type="button" class="btn-close" @onclick="() => _errorMessage = null"
                        aria-label="Close"></button>
            </div>
        }
    }
</div>

@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private sealed class ChannelState
    {
        public required string Name { get; init; }
        public bool Muted { get; set; }
    }

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _channels = _prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private void ToggleChannel(string name, bool muted)
    {
        var channel = _channels.FirstOrDefault(c => c.Name == name);
        if (channel is not null)
        {
            channel.Muted = muted;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _successMessage = "Notification preferences saved!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save preferences: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex align-items-center justify-content-between"
         role="button" @onclick="() => _expanded = !_expanded"
         aria-expanded="@_expanded">
        <h5 class="mb-0">Change Password</h5>
        <span class="bi @(_expanded ? "bi-chevron-up" : "bi-chevron-down")"></span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label for="currentPassword" class="form-label">Current Password</label>
                <input id="currentPassword" type="password" class="form-control"
                       @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label for="newPassword" class="form-label">New Password</label>
                <input id="newPassword" type="password" class="form-control"
                       @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label for="confirmPassword" class="form-label">Confirm New Password</label>
                <input id="confirmPassword" type="password" class="form-control"
                       @bind="_confirmPassword" />
            </div>

