@code {
    private NotificationPrefs? _prefs;
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelState> _channels = [];
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private sealed class ChannelState
    {
        public required string Name { get; init; }
        public bool Muted { get; set; }
    }

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = _prefs.EmailNotifications;
        _pushNotifications = _prefs.PushNotifications;
        _weeklyDigest = _prefs.WeeklyDigest;
        _channels = _prefs.MutedChannels
            .Select(c => new ChannelState { Name = c, Muted = true })
            .ToList();
        _loading = false;
    }

    private void ToggleChannel(string name, bool muted)
    {
        var channel = _channels.FirstOrDefault(c => c.Name == name);
        if (channel is not null)
        {
            channel.Muted = muted;
        }
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var mutedChannels = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
            var updated = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedChannels);
            await SettingsService.SaveNotificationPrefsAsync(updated);
            _prefs = updated;
            _successMessage = "Notification preferences saved!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save preferences: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

