@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex align-items-center justify-content-between"
         role="button" @onclick="() => _expanded = !_expanded"
         aria-expanded="@_expanded">
        <h5 class="mb-0">Change Password</h5>
        <span class="bi @(_expanded ? "bi-chevron-up" : "bi-chevron-down")"></span>
    </div>

    @if (_expanded)
    {
        <div class="card-body">
            <div class="mb-3">
                <label for="currentPassword" class="form-label">Current Password</label>
                <input id="currentPassword" type="password" class="form-control"
                       @bind="_currentPassword" />
            </div>

            <div class="mb-3">
                <label for="newPassword" class="form-label">New Password</label>
                <input id="newPassword" type="password" class="form-control"
                       @bind="_newPassword" />
            </div>

            <div class="mb-3">
                <label for="confirmPassword" class="form-label">Confirm New Password</label>
                <input id="confirmPassword" type="password" class="form-control"
                       @bind="_confirmPassword" />
            </div>

            @if (_validationError is not null)
            {
                <div class="alert alert-warning py-2" role="alert">@_validationError</div>
            }

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@_saving">
                @if (_saving)
                {
                    <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
                }
                Update Password
            </button>

            @if (_successMessage is not null)
            {
                <div class="alert alert-success mt-3 py-2" role="alert">@_successMessage</div>
            }

            @if (_errorMessage is not null)
            {
                <div class="alert alert-danger mt-3 py-2" role="alert">@_errorMessage</div>
            }
        </div>
    }
</div>

@code {
    private bool _expanded;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _saving;
    private string? _validationError;
    private string? _successMessage;
    private string? _errorMessage;

    private async Task UpdatePasswordAsync()
    {
        _validationError = null;
        _successMessage = null;
        _errorMessage = null;

        if (string.IsNullOrWhiteSpace(_currentPassword))
        {
            _validationError = "Current password is required.";
            return;
        }

        if (string.IsNullOrWhiteSpace(_newPassword))
        {
            _validationError = "New password is required.";
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            _validationError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _successMessage = "Password updated successfully!";
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to change password: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

