namespace sv_aea6abbb8423404ca5a9219d439b3479.Services;

public record UserProfile(string DisplayName, string Email, string AvatarUrl, string Bio);

public record NotificationPrefs(
    bool EmailNotifications,
    bool PushNotifications,
    bool WeeklyDigest,
    List<string> MutedChannels);

public record SecuritySettings(
    bool TwoFactorEnabled,
    DateTime? LastPasswordChange,
    List<ActiveSession> Sessions);

public record ActiveSession(string Id, string Device, string Location, DateTime LastActive);

public record AppearanceSettings(string Theme, string FontSize, string Language, bool CompactMode);

public interface ISettingsService
{
    Task<UserProfile> GetProfileAsync();
    Task SaveProfileAsync(UserProfile profile);
    Task<NotificationPrefs> GetNotificationPrefsAsync();
    Task SaveNotificationPrefsAsync(NotificationPrefs prefs);
    Task<SecuritySettings> GetSecuritySettingsAsync();
    Task ChangePasswordAsync(string currentPassword, string newPassword);
    Task RevokeSessionAsync(string sessionId);
    Task<AppearanceSettings> GetAppearanceAsync();
    Task SaveAppearanceAsync(AppearanceSettings settings);
}

@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Security Settings</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else if (_settings is not null)
    {
        <ChangePasswordPanel />

        <div class="card mb-4">
            <div class="card-body">
                <div class="d-flex align-items-center justify-content-between">
                    <div>
                        <h5 class="mb-1">Two-Factor Authentication</h5>
                        <p class="text-muted mb-0">
                            @if (_settings.TwoFactorEnabled)
                            {
                                <span class="badge bg-success me-1">Enabled</span>
                                <span>Your account is protected with 2FA.</span>
                            }
                            else
                            {
                                <span class="badge bg-warning text-dark me-1">Disabled</span>
                                <span>Enable 2FA for additional security.</span>
                            }
                        </p>
                    </div>
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               id="twoFactor" checked="@_settings.TwoFactorEnabled" disabled
                               aria-label="Two-factor authentication status" />
                    </div>
                </div>
                @if (_settings.LastPasswordChange.HasValue)
                {
                    <small class="text-muted mt-2 d-block">
                        Last password change: @_settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                    </small>
                }
            </div>
        </div>

        <div class="card mb-4">
            <div class="card-header">
                <h5 class="mb-0">Active Sessions</h5>
            </div>
            <div class="card-body p-0">
                @if (_settings.Sessions.Count == 0)
                {
                    <p class="text-muted p-3 mb-0">No active sessions.</p>
                }
                else
                {
                    <div class="table-responsive">
                        <table class="table table-hover mb-0">
                            <thead>
                                <tr>
                                    <th>Device</th>
                                    <th>Location</th>
                                    <th>Last Active</th>
                                    <th class="text-end">Action</th>
                                </tr>
                            </thead>
                            <tbody>
                                @foreach (var session in _settings.Sessions)
                                {
                                    var isCurrent = session == _settings.Sessions.FirstOrDefault();
                                    <tr>
                                        <td>
                                            @session.Device
                                            @if (isCurrent)
                                            {
                                                <span class="badge bg-info ms-1">Current</span>
                                            }
                                        </td>
                                        <td>@session.Location</td>
                                        <td>@session.LastActive.ToString("g")</td>
                                        <td class="text-end">
                                            @if (!isCurrent)
                                            {
                                                <button class="btn btn-outline-danger btn-sm"
                                                        @onclick="() => _sessionToRevoke = session">
                                                    Revoke
                                                </button>
                                            }
                                        </td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                }
            </div>
        </div>

        @if (_errorMessage is not null)
        {
            <div class="alert alert-danger alert-dismissible" role="alert">
                @_errorMessage
                <button type="button" class="btn-close" @onclick="() => _errorMessage = null"
                        aria-label="Close"></button>
            </div>
        }

        <RevokeSessionDialog Session="@_sessionToRevoke"
                             OnConfirm="RevokeSessionAsync"
                             OnCancel="() => _sessionToRevoke = null" />
    }
</div>

@code {
    private SecuritySettings? _settings;
    private ActiveSession? _sessionToRevoke;
    private bool _loading = true;
    private string? _errorMessage;

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        _settings = await SettingsService.GetSecuritySettingsAsync();
        _loading = false;
    }

    private async Task RevokeSessionAsync()
    {
        if (_sessionToRevoke is null || _settings is null)
            return;

        var sessionId = _sessionToRevoke.Id;
        _sessionToRevoke = null;
        _errorMessage = null;

        try
        {
            await SettingsService.RevokeSessionAsync(sessionId);
            var updatedSessions = _settings.Sessions.Where(s => s.Id != sessionId).ToList();
            _settings = _settings with { Sessions = updatedSessions };
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to revoke session: {ex.Message}";
        }
    }
}

@using sv_aea6abbb8423404ca5a9219d439b3479.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3 class="mb-4">Appearance</h3>

    @if (_loading)
    {
        <div class="d-flex justify-content-center py-5">
            <div class="spinner-border" role="status">
                <span class="visually-hidden">Loading...</span>
            </div>
        </div>
    }
    else
    {
        <div class="row">
            <div class="col-md-7">
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in _themes)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="theme-@theme" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="theme-@theme">@theme</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in _fontSizes)
                    {
                        <div class="form-check form-check-inline">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="font-@size" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="font-@size">@size</label>
                        </div>
                    }
                </div>

                <div class="mb-4">
                    <label for="language" class="form-label"><h5 class="d-inline">Language</h5></label>
                    <select id="language" class="form-select" style="max-width: 250px;"
                            @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang.Key">@lang.Value</option>
                        }
                    </select>
                </div>

                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" role="switch"
                               id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @if (_saving)
                    {
                        <span class="spinner-border spinner-border-sm me-1" aria-hidden="true"></span>
                    }
                    Save
                </button>

                @if (_successMessage is not null)
                {
                    <div class="alert alert-success alert-dismissible mt-3" role="alert">
                        @_successMessage
                        <button type="button" class="btn-close" @onclick="() => _successMessage = null"
                                aria-label="Close"></button>
                    </div>
                }

                @if (_errorMessage is not null)
                {
                    <div class="alert alert-danger alert-dismissible mt-3" role="alert">
                        @_errorMessage
                        <button type="button" class="btn-close" @onclick="() => _errorMessage = null"
                                aria-label="Close"></button>
                    </div>
                }
            </div>

            <div class="col-md-5">
                <h5>Preview</h5>
                <div class="appearance-preview border rounded p-3 @PreviewThemeClass"
                     style="@PreviewFontStyle">
                    <div class="@(_compactMode ? "mb-1" : "mb-3")">
                        <strong>Sample Heading</strong>
                    </div>
                    <p class="@(_compactMode ? "mb-1" : "mb-2")">
                        This is how your content will look with the selected settings.
                    </p>
                    <div class="d-flex gap-2 @(_compactMode ? "mb-1" : "mb-2")">
                        <span class="badge bg-primary">Tag</span>
                        <span class="badge bg-secondary">Label</span>
                    </div>
                    <button class="btn btn-sm btn-outline-primary" disabled>Sample Button</button>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "en";
    private bool _compactMode;
    private bool _loading = true;
    private bool _saving;
    private string? _successMessage;
    private string? _errorMessage;

    private static readonly string[] _themes = ["Light", "Dark", "System"];
    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private static readonly Dictionary<string, string> _languages = new()
    {
        ["en"] = "English",
        ["es"] = "Spanish",
        ["fr"] = "French",
        ["de"] = "German",
        ["ja"] = "Japanese",
        ["zh"] = "Chinese",
    };

    private string PreviewThemeClass => _theme switch
    {
        "Dark" => "bg-dark text-light",
        "Light" => "bg-white text-dark",
        _ => "bg-light text-dark"
    };

    private string PreviewFontStyle => _fontSize switch
    {
        "Small" => "font-size: 0.85rem;",
        "Large" => "font-size: 1.2rem;",
        _ => "font-size: 1rem;"
    };

    protected override async Task OnInitializedAsync()
    {
        _loading = true;
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _successMessage = null;
        _errorMessage = null;
        try
        {
            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            _successMessage = "Appearance settings saved!";
        }
        catch (Exception ex)
        {
            _errorMessage = $"Failed to save settings: {ex.Message}";
        }
        finally
        {
            _saving = false;
        }
    }
}

