+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "en";
+    private bool _compactMode;
+    private bool _loading = true;
+    private bool _saving;
+    private string? _successMessage;
+    private string? _errorMessage;
+
+    private static readonly string[] _themes = ["Light", "Dark", "System"];
+    private static readonly string[] _fontSizes = ["Small", "Medium", "Large"];
+    private static readonly Dictionary<string, string> _languages = new()
+    {
+        ["en"] = "English",
+        ["es"] = "Spanish",
+        ["fr"] = "French",
+        ["de"] = "German",
+        ["ja"] = "Japanese",
+        ["zh"] = "Chinese",
+    };
+
+    private string PreviewThemeClass => _theme switch
+    {
+        "Dark" => "bg-dark text-light",
+        "Light" => "bg-white text-dark",
+        _ => "bg-light text-dark"
+    };
+
+    private string PreviewFontStyle => _fontSize switch
+    {
+        "Small" => "font-size: 0.85rem;",
+        "Large" => "font-size: 1.2rem;",
+        _ => "font-size: 1rem;"
+    };
+
+    protected override async Task OnInitializedAsync()
+    {
+        _loading = true;
+        var settings = await SettingsService.GetAppearanceAsync();
+        _theme = settings.Theme;
+        _fontSize = settings.FontSize;
+        _language = settings.Language;
+        _compactMode = settings.CompactMode;
+        _loading = false;
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        _successMessage = null;
+        _errorMessage = null;
+        try
+        {
+            var updated = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+            await SettingsService.SaveAppearanceAsync(updated);
+            _successMessage = "Appearance settings saved!";
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = $"Failed to save settings: {ex.Message}";
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

