@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-nav">
        <SettingsSidebar ActiveSection="@_activeSection"
                         OnSectionChanged="section => _activeSection = section" />
    </div>
    <div class="settings-content">
        @switch (_activeSection)
        {
            case "profile":
                <ProfileSection />
                break;
            case "notifications":
                <NotificationsSection />
                break;
            case "security":
                <SecuritySection />
                break;
            case "appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "profile";
}

.settings-dashboard {
    display: flex;
    gap: 2rem;
    min-height: 500px;
}

.settings-nav {
    flex: 0 0 220px;
}

.settings-content {
    flex: 1;
    min-width: 0;
}

/* Sidebar styling */
::deep .settings-sidebar .nav-link {
    color: var(--bs-body-color);
    border-radius: 0.375rem;
    padding: 0.625rem 1rem;
    margin-bottom: 0.25rem;
    transition: background-color 0.15s;
}

::deep .settings-sidebar .nav-link:hover {
    background-color: var(--bs-tertiary-bg);
}

::deep .settings-sidebar .nav-link.active {
    background-color: var(--bs-primary);
    color: #fff;
}

/* Preview area */
::deep .appearance-preview {
    min-height: 160px;
    transition: all 0.2s ease;
}

/* Modal backdrop z-index fix */
::deep .modal-backdrop {
    z-index: 1040;
}

::deep .modal {
    z-index: 1050;
}

/* Responsive: stack on small screens */
@media (max-width: 768px) {
    .settings-dashboard {
        flex-direction: column;
        gap: 1rem;
    }

    .settings-nav {
        flex: none;
    }

    ::deep .settings-sidebar .nav {
        flex-direction: row !important;
        overflow-x: auto;
    }

    ::deep .settings-sidebar .nav-link {
        white-space: nowrap;
    }
}

